def load_form_schema():
    """Load form schema from current_event_form.json or query parameter."""
    import glob
    
    # Try multiple possible locations (local, subfolder, etc)
    possible_paths = [
        "current_event_form.json",
        "./current_event_form.json",
        "../current_event_form.json",
        "python-langchain/current_event_form.json",
    ]
    
    for form_file in possible_paths:
        if os.path.exists(form_file):
            try:
                with open(form_file, 'r') as f:
                    # Return form without displaying message (admin will see status in sidebar)
                    return json.load(f)
            except Exception as e:
                # Silent fail, will use default form
                pass
    
    # If no form file found, use default
    return get_default_form()

