# SQLite DATABASE SETUP (Dynamic based on event)
# ============================================================================

def get_db_connection():
    conn = sqlite3.connect(DB_PATH)
    return conn

def create_table_if_not_exists(fields, event_det):
    """Build dynamic SQL table based on form fields and event details."""
    # Filter out section headers (they don't have 'name' key)
    actual_fields = [f for f in fields if f.get('type') != 'section_header' and 'name' in f]
    
    # Build SQL for dynamic fields
    columns = [
        f"{f['name']} TEXT" if f["type"] not in ["number", "date", "checkbox"] else (
            f"{f['name']} INTEGER" if f["type"] == "number" else (
                f"{f['name']} BOOLEAN" if f["type"] == "checkbox" else f"{f['name']} TEXT"
            )
        )
        for f in actual_fields
    ]
    # Add metadata columns (timestamp + event details)
    columns += [
        "timestamp TEXT",
        "event_name TEXT",
        "event_date TEXT",
        "event_time TEXT",
        "event_location TEXT",
        "event_max_participants INTEGER",
        "event_age_range TEXT"
    ]
    sql = f"CREATE TABLE IF NOT EXISTS {TABLE_NAME} (id INTEGER PRIMARY KEY AUTOINCREMENT, {', '.join(columns)})"
    with get_db_connection() as conn:
        conn.execute(sql)
        conn.commit()

def insert_registration(submission):
    keys = list(submission.keys())
    values = [submission[k] for k in keys]
    placeholders = ",".join(["?" for _ in keys])
    sql = f"INSERT INTO {TABLE_NAME} ({', '.join(keys)}) VALUES ({placeholders})"
    with get_db_connection() as conn:
        conn.execute(sql, values)
        conn.commit()

def get_all_registrations():
    with get_db_connection() as conn:
        df = pd.read_sql_query(f"SELECT * FROM {TABLE_NAME}", conn)
    return df

def generate_csv_with_metadata(registrations_df, event_details):
    """Generate CSV export with event metadata header."""
    if registrations_df.empty:
        return None
    
    # Create StringIO object for CSV content
    csv_buffer = StringIO()
    
    # Add metadata header
    csv_buffer.write(f"Event Registration Export\n")
    csv_buffer.write(f"Event: {event_details.get('event_name', 'Unknown')}\n")
    csv_buffer.write(f"Date: {event_details.get('date', 'TBD')}\n")
    csv_buffer.write(f"Time: {event_details.get('time', 'TBD')}\n")
    csv_buffer.write(f"Location: {event_details.get('location', 'TBD')}\n")
    csv_buffer.write(f"Exported: {datetime.datetime.now().strftime('%B %d, %Y at %I:%M %p')}\n")
    csv_buffer.write(f"Total Registrations: {len(registrations_df)}\n")
    csv_buffer.write("\n")  # Blank line separator
    
    # Write the actual CSV data
    registrations_df.to_csv(csv_buffer, index=False)
    
    return csv_buffer.getvalue()

def setup_waiver_directory() -> str:
    """Create directory structure for storing waivers."""
    waivers_dir = os.path.join(os.path.dirname(__file__), "waivers")
    if not os.path.exists(waivers_dir):
        os.makedirs(waivers_dir)
    return waivers_dir

def process_waiver_submission(form_values, event_details):
    """Process and store waiver submission if waiver fields exist."""
    if not WAIVER_ENABLED:
        return None
    
    # Check if waiver fields exist in the form
    waiver_fields = ['waiver_acknowledgment', 'waiver_signature', 'waiver_date']
    has_waiver_fields = any(field in form_values for field in waiver_fields)
    
    if not has_waiver_fields:
        return None
    
    # Validate waiver acknowledgment
    if not form_values.get('waiver_acknowledgment', False):
        return {'status': 'error', 'message': '❌ You must acknowledge the waiver to continue'}
    
    # Ensure waiver signature is provided
    if not form_values.get('waiver_signature', '').strip():
        return {'status': 'error', 'message': '❌ Waiver signature is required'}
    
    try:
        # Save the signed waiver
        waiver_result = save_signed_waiver(
            participant_info=form_values,
            event_name=event_details.get('event_name', 'Unknown Event')
        )
        return {'status': 'success', 'result': waiver_result}
    except Exception as e:
        return {'status': 'error', 'message': f'❌ Error processing waiver: {str(e)}'}

